urlset:
{% for sitemap_entry in entries %}

    {{ sitemap_entry.permalink | safe }}
    {% if sitemap_entry.updated %}
    {{ sitemap_entry.updated }}
    {% elif sitemap_entry.date %}
    {{ sitemap_entry.date }}
    {% endif %}
    {% if sitemap_entry.permalink == "https://pwnforfunandprofit.xyz/" %}
    daily
    1.0
    {% else %}
    weekly
    0.5
    {% endif %}

{% endfor %}
